// H498: video_export is a utility (MediaRecorder → WebM), not an analytical
// finding — spec §4.1 says it "belongs behind a 'tools' divider, not in the
// gallery proper". Generated into its own folder, positioned after the six
// themes so it never competes with them for prominence.
const TOOLS = {
  slug: 'instrumenty',
  title: 'Инструменты',
  title_en: 'Tools',
  pages: [
    { slug: 'video_export', file: 'afanasy_video_export.html', title: 'Экспорт видео',
      source: `инструмент (MediaRecorder → WebM) поверх тайм-лапса маршрута; не визуализация-находка, а утилита; ${D}`,
      title_en: 'Video Export',
      source_en: `a tool (MediaRecorder → WebM) built on top of the route time-lapse; not an analytical finding but a utility; ${D_EN}` },
  ],
};

let position = 1;

function pageMdx(page, titleKey, sourceKey) {
  const yamlTitle = JSON.stringify(page[titleKey]);
  return `---
title: ${yamlTitle}
---

${GENERATED_HEADER}# ${page[titleKey]}

<AtlasFigure src="${page.file}" title={${yamlTitle}} caption={${yamlTitle}} source={${JSON.stringify(page[sourceKey])}} />
`;
}

function writeSection(section) {
  const dir = join(outDir, section.slug);
  mkdirSync(dir, { recursive: true });
  writeFileSync(
    join(dir, '_category_.json'),
    JSON.stringify({ label: section.title, position: position++, link: { type: 'generated-index' } }, null, 2) + '\n',
  );
  for (const page of section.pages) {
    writeFileSync(join(dir, `${page.slug}.mdx`), pageMdx(page, 'title', 'source'));
  }

  const i18nDir = join(i18nOutDir, section.slug);
  mkdirSync(i18nDir, { recursive: true });
  for (const page of section.pages) {
    writeFileSync(join(i18nDir, `${page.slug}.mdx`), pageMdx(page, 'title_en', 'source_en'));
  }
}

for (const theme of THEMES) writeSection(theme);
writeSection(TOOLS);

console.log(
  `[generate-atlas-mdx] wrote ${THEMES.reduce((n, t) => n + t.pages.length, 0)} figure pages (ru+en) across ${THEMES.length} themes + ${TOOLS.pages.length} tool page`,
);
